import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def pkg_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                m[(name, pkg['id'])] = pkg['resolvedVersion']
    return m

b = pkg_map(baseline)
a = pkg_map(after)
changes = []
for k in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    status = 'Unchanged' if bv == av else 'CHANGED'
    if status == 'CHANGED':
        changes.append(f'{k[0]:20s} {k[1]:45s} {bv:>10s} -> {av}')
    print(f'{k[0]:20s} {k[1]:45s} {bv:>10s} -> {av:>10s}  {status}')
if not changes:
    print('\nAll packages resolve identically. Conversion is version-neutral.')
"

